insert into public.lessons (remote_id, course_remote_id, type, title, duration_seconds, order_index, xp_reward, content_json) values
('mil-1-1', 'mil-1', 'theory', 'Що таке MARCH?', 300, 0, 10, '{"title":"Що таке MARCH?","blocks":[{"type":"heading","text":"MARCH — алгоритм порятунку","level":1},{"type":"text","text":"MARCH — це акронім, який використовують медики НАТО для пріоритетної оцінки поранених у бойових умовах."},{"type":"warning","text":"Порядок букв = порядок дій. Ніколи не пропускайте етапи!"},{"type":"heading","text":"Розшифровка","level":2},{"type":"text","text":"M — Massive hemorrhage (Масивна кровотеча)\nA — Airway (Дихальні шляхи)\nR — Respiration (Дихання)\nC — Circulation (Кровообіг)\nH — Hypothermia (Гіпотермія)"},{"type":"info","text":"Масивна кровотеча — головна причина запобіжних смертей на полі бою. Саме тому вона стоїть першою."},{"type":"text","text":"Кожен етап MARCH вимагає конкретних дій та обладнання. У наступних уроках ми розглянемо кожен етап детально."}],"keyTerms":["MARCH","Масивна кровотеча","Дихальні шляхи","Гіпотермія","Тактична медицина"]}'),
('mil-1-2', 'mil-1', 'quiz', 'Тест: MARCH алгоритм', 180, 1, 10, '{"questions":[{"question":"Що означає буква M у MARCH?","options":["Medical aid","Massive hemorrhage","Movement","Morphine"],"correctIndex":1,"explanation":"M = Massive hemorrhage — масивна кровотеча. Це перший і найважливіший крок."},{"question":"Який правильний порядок MARCH?","options":["Airway → Breathing → Circulation","Massive hemorrhage → Airway → Respiration → Circulation → Hypothermia","Hypothermia → Circulation → Respiration","Circulation → Airway → Massive hemorrhage"],"correctIndex":1},{"question":"Чому масивна кровотеча стоїть першою?","options":["Бо її легше лікувати","Бо це головна причина запобіжних смертей","Бо так зручніше запам''ятати","Бо інші етапи менш важливі"],"correctIndex":1}]}'),
('mil-1-3', 'mil-1', 'checklist', 'Чеклист: MARCH на практиці', 240, 2, 10, '{"steps":[{"title":"M — Зупинити кровотечу","description":"Накласти турнікет або тиснучу пов''язку на місце масивної кровотечі"},{"title":"A — Відкрити дихальні шляхи","description":"Перевірити прохідність дихальних шляхів, за потреби — назофарингеальний повітровод"},{"title":"R — Перевірити дихання","description":"Огляд грудної клітки на наявність ран, накласти chest seal за потреби"},{"title":"C — Оцінити кровообіг","description":"Перевірити пульс, накласти IV доступ за потреби"},{"title":"H — Запобігти гіпотермії","description":"Вкрити постраждалого термоковдрою, ізолювати від землі"}]}')
insert into public.lessons (remote_id, course_remote_id, type, title, duration_seconds, order_index, xp_reward, content_json) values
('mil-4-1', 'mil-4', 'theory', 'M: Зупинка масивної кровотечі', 420, 0, 10, '{"title":"M — Massive bleeding","blocks":[{"type":"heading","text":"Зупинка масивної кровотечі — перший пріоритет","level":1},{"type":"text","text":"Критична крововтрата може вбити за 2-3 хвилини, тому етап M завжди виконується першим."},{"type":"warning","text":"Поки кровотечу не зупинено, інші втручання мають другорядний пріоритет."},{"type":"heading","text":"Що робити покроково","level":2},{"type":"text","text":"1) Визначте джерело кровотечі.\\n2) Накладіть турнікет на 5-8 см вище рани або максимально високо, якщо рану не видно.\\n3) Затягніть до повної зупинки кровотечі.\\n4) За потреби накладіть другий турнікет вище першого.\\n5) Для зон без можливості турнікета використайте гемостатик і тиснучу пов''язку.\\n6) Обов''язково зафіксуйте час накладання."},{"type":"info","text":"Навичка швидкого накладання турнікета під стресом рятує життя частіше за складні маніпуляції."}],"keyTerms":["Massive bleeding","Турнікет","Гемостатик","Тиснуча пов''язка","Час накладання"]}'),
('mil-4-2', 'mil-4', 'quiz', 'Тест: M — Massive bleeding', 180, 1, 10, '{"questions":[{"question":"Що виконується першим за алгоритмом MARCH?","options":["Відновлення дихання","Зупинка масивної кровотечі","Оцінка свідомості","Профілактика гіпотермії"],"correctIndex":1},{"question":"Якщо джерело кровотечі з кінцівки не видно, турнікет ставлять:","options":["На суглоб","Максимально високо на кінцівку","Нижче рани","Лише на оголену шкіру"],"correctIndex":1},{"question":"Що обов''язково зробити після накладання турнікета?","options":["Дати воду","Записати час накладання","Зняти через 5 хвилин","Накрити бинтом"],"correctIndex":1,"explanation":"Фіксація часу потрібна для подальшого безпечного ведення постраждалого."}]}'),
('mil-4-3', 'mil-4', 'theory', 'A: Контроль дихальних шляхів', 420, 2, 10, '{"title":"A — Airway","blocks":[{"type":"heading","text":"Контроль і забезпечення дихальних шляхів","level":1},{"type":"text","text":"Після зупинки масивної кровотечі потрібно переконатись, що повітря вільно проходить у легені."},{"type":"warning","text":"Навіть ідеально зупинена кровотеча не врятує, якщо немає прохідних дихальних шляхів."},{"type":"heading","text":"Базові дії","level":2},{"type":"text","text":"1) Оцініть наявність дихання (дивлюсь-слухаю-відчуваю).\\n2) Очистіть рот від видимих сторонніх мас.\\n3) Виконайте маневр висунення нижньої щелепи або підйом підборіддя.\\n4) Якщо постраждалий без свідомості, але дихає — стабільне бокове положення.\\n5) За наявності навичок використайте назофарингеальний повітровід."},{"type":"info","text":"Якщо постраждалий свідомий і сам обирає позу, в якій легше дихати, не заважайте цій позиції."}],"keyTerms":["Airway","Прохідність дихальних шляхів","Маневр щелепи","НПП","Стабільне бокове положення"]}'),
('mil-4-4', 'mil-4', 'quiz', 'Тест: A — Airway', 180, 3, 10, '{"questions":[{"question":"Яка ціль етапу A у MARCH?","options":["Профілактика шоку","Забезпечити прохідність дихальних шляхів","Провести декомпресію","Зупинити кровотечу"],"correctIndex":1},{"question":"Постраждалий без свідомості, але дихає. Найкраща дія:","options":["Посадити його","Покласти у стабільне бокове положення","Виконати СЛР","Накласти турнікет"],"correctIndex":1},{"question":"Назофарингеальний повітровід застосовують, щоб:","options":["Підвищити тиск","Підтримати прохідність дихальних шляхів","Зупинити кровотечу","Зменшити біль"],"correctIndex":1}]}'),
('mil-4-5', 'mil-4', 'theory', 'R: Оцінка та підтримка дихання', 420, 4, 10, '{"title":"R — Respiration","blocks":[{"type":"heading","text":"Оцінка і стабілізація дихання","level":1},{"type":"text","text":"На цьому етапі перевіряють ефективність дихання та виключають небезпечні поранення грудної клітки."},{"type":"warning","text":"Відкрита рана грудної клітки може швидко призвести до критичного стану."},{"type":"heading","text":"Що контролюємо","level":2},{"type":"text","text":"1) Частоту і глибину дихання.\\n2) Наявність поранень грудної клітки спереду і зі спини.\\n3) Ознаки погіршення після накладання оклюзійної наліпки.\\n4) Положення тіла, у якому постраждалому легше дихати."},{"type":"info","text":"За підозри на напружений пневмоторакс потрібні дії згідно з підготовкою і протоколом підрозділу."}],"keyTerms":["Respiration","Chest Seal","Пневмоторакс","Оклюзійна наліпка","Оцінка дихання"]}'),
('mil-4-6', 'mil-4', 'quiz', 'Тест: R — Respiration', 180, 5, 10, '{"questions":[{"question":"Що є ключовою дією при відкритій рані грудної клітки?","options":["Накласти джгут","Накласти оклюзійну наліпку","Дати знеболювальне","Посадити постраждалого"],"correctIndex":1},{"question":"Чому важливо оглядати грудну клітку ще й зі спини?","options":["Щоб перевірити пульс","Можливий другий (вихідний) отвір рани","Щоб накласти пов''язку на шию","Щоб зняти одяг"],"correctIndex":1},{"question":"Літера R у MARCH означає:","options":["Recovery","Respiration","Rescue","Reassessment"],"correctIndex":1}]}'),
('mil-4-7', 'mil-4', 'theory', 'C: Відновлення кровообігу', 420, 6, 10, '{"title":"C — Circulation","blocks":[{"type":"heading","text":"Відновлення та контроль кровообігу","level":1},{"type":"text","text":"Після M-A-R етап C допомагає виявити приховану крововтрату і ранні ознаки шоку."},{"type":"warning","text":"Шок розвивається поступово: не пропустіть блідість, холодний піт, сплутаність свідомості."},{"type":"heading","text":"Дії на етапі C","level":2},{"type":"text","text":"1) Перевірте раніше накладені турнікети і бандажі.\\n2) Проведіть повторний огляд від голови до ніг.\\n3) Оцініть периферичний пульс і стан свідомості.\\n4) За потреби посильте контроль кровотечі.\\n5) Підготуйте постраждалого до швидкої евакуації."},{"type":"info","text":"Мета етапу C — не лише знайти проблему, а й не допустити погіршення до передачі медичній ланці."}],"keyTerms":["Circulation","Шок","Периферичний пульс","Повторний огляд","Евакуація"]}'),
('mil-4-8', 'mil-4', 'quiz', 'Тест: C — Circulation', 180, 7, 10, '{"questions":[{"question":"Що перевіряють на етапі C у першу чергу?","options":["Лише зіниці","Кровообіг і ознаки шоку","Тільки температуру тіла","Тільки біль"],"correctIndex":1},{"question":"Слабкий периферичний пульс може свідчити про:","options":["Норму після стресу","Початок шоку","Гіпервентиляцію","Переохолодження без крововтрати"],"correctIndex":1},{"question":"Чому потрібен повторний огляд після M-A-R?","options":["Для звітності","Щоб знайти приховані ушкодження та крововтрату","Щоб скоротити час евакуації","Щоб визначити групу крові"],"correctIndex":1}]}'),
('mil-4-9', 'mil-4', 'theory', 'H: Гіпотермія і травма голови', 420, 8, 10, '{"title":"H — Hypothermia / Head injury","blocks":[{"type":"heading","text":"Профілактика гіпотермії і контроль травми голови","level":1},{"type":"text","text":"Навіть у теплу погоду постраждалий з крововтратою швидко втрачає тепло, що погіршує прогноз."},{"type":"warning","text":"Гіпотермія посилює коагулопатію та підвищує ризик смерті, поэтому етап H обов''язковий."},{"type":"heading","text":"Практичні дії","level":2},{"type":"text","text":"1) Ізолюйте постраждалого від землі.\\n2) Укутайте термоковдрою або сухими речами.\\n3) При підозрі на ЧМТ контролюйте свідомість і зіниці.\\n4) Не видаляйте сторонні предмети з рани голови/ока.\\n5) Продовжуйте моніторинг до евакуації."},{"type":"info","text":"Етап H завершує первинну стабілізацію і готує постраждалого до безпечного транспортування."}],"keyTerms":["Hypothermia","Head injury","Термоковдра","Моніторинг свідомості","ЧМТ"]}'),
('mil-4-10', 'mil-4', 'quiz', 'Тест: H — Hypothermia / Head injury', 180, 9, 10, '{"questions":[{"question":"Навіть у теплу погоду постраждалий може мати гіпотермію через:","options":["Сонячний удар","Крововтрату і шок","Наявність пов''язки","Високу вологість"],"correctIndex":1},{"question":"Що НЕ можна робити при проникаючій травмі ока/черепа?","options":["Контролювати стан","Накласти пов''язку","Витягати сторонній предмет","Підготувати евакуацію"],"correctIndex":2},{"question":"Яка дія належить до етапу H?","options":["Накладання турнікета","Ізоляція від холодної поверхні","Маневр висунення щелепи","Накладання chest seal"],"correctIndex":1}]}')
insert into public.lessons (remote_id, course_remote_id, type, title, duration_seconds, order_index, xp_reward, content_json) values
('civ-1-1', 'civ-1', 'theory', 'Оцінка ситуації', 300, 0, 10, '{"title":"Оцінка ситуації","blocks":[{"type":"heading","text":"Безпека — перш за все","level":1},{"type":"text","text":"Перед наданням першої допомоги завжди оцініть ситуацію. Ви не зможете допомогти, якщо самі станете постраждалим."},{"type":"warning","text":"Ніколи не наближайтесь до постраждалого, якщо місце небезпечне!"},{"type":"heading","text":"Алгоритм дій","level":2},{"type":"text","text":"1. Оцініть безпеку\\n2. Перевірте свідомість постраждалого\\n3. Викличте 103 (швидка)\\n4. Надайте першу допомогу\\n5. Не залишайте постраждалого до приїзду медиків"},{"type":"info","text":"Номер екстреної допомоги в Україні: 103 (швидка), 101 (пожежна), 102 (поліція), або єдиний 112."}],"keyTerms":["Безпека","103","Свідомість","Алгоритм дій","Екстрена допомога"]}'),
('civ-1-2', 'civ-1', 'quiz', 'Тест: Базові принципи', 180, 1, 10, '{"questions":[{"question":"Що потрібно зробити ПЕРШИМ при наданні допомоги?","options":["Почати СЛР","Оцінити безпеку","Зателефонувати 103","Накласти пов''язку"],"correctIndex":1},{"question":"Який номер швидкої допомоги в Україні?","options":["911","103","112","101"],"correctIndex":1,"explanation":"103 — швидка допомога. 112 — єдиний номер екстреної допомоги."},{"question":"Що робити, якщо місце небезпечне?","options":["Все одно допомагати","Чекати допомоги та не наближатись","Тікати","Кричати"],"correctIndex":1}]}'),
('civ-1-3', 'civ-1', 'checklist', 'Чеклист: Аптечка', 180, 2, 10, '{"steps":[{"title":"Аптечка першої допомоги","description":"Перевірте наявність: бинти, пластирі, антисептик, рукавички"},{"title":"Рукавички","description":"Нітрилові або латексні рукавички — 2-3 пари"},{"title":"Бинти та серветки","description":"Стерильні марлеві серветки різних розмірів"},{"title":"Антисептик","description":"Хлоргексидин або перекис водню"},{"title":"Ножиці та пінцет","description":"Для розрізання одягу та видалення сторонніх предметів"}]}'),
('civ-2-1', 'civ-2', 'theory', 'Як виконувати СЛР', 360, 0, 10, '{"title":"Серцево-легенева реанімація","blocks":[{"type":"heading","text":"СЛР — врятуй життя за 5 хвилин","level":1},{"type":"text","text":"Серцево-легенева реанімація (СЛР) — це комплекс дій для підтримки кровообігу та дихання у людини із зупинкою серця."},{"type":"warning","text":"Мозок починає гинути через 4-6 хвилин без кисню. Кожна секунда на рахунку!"},{"type":"heading","text":"Техніка компресій","level":2},{"type":"text","text":"• Глибина: 5-6 см\\n• Частота: 100-120 на хвилину\\n• Співвідношення: 30 компресій : 2 вдихи\\n• Місце: нижня третина грудини"},{"type":"info","text":"Натискайте в ритмі пісні Staying Alive — це приблизно 100-120 ударів на хвилину."}],"keyTerms":["СЛР","Компресії грудної клітки","AED","30:2","Зупинка серця"]}'),
('civ-2-2', 'civ-2', 'quiz', 'Тест: СЛР', 180, 1, 10, '{"questions":[{"question":"Яка глибина компресій при СЛР для дорослого?","options":["2-3 см","5-6 см","8-10 см","1-2 см"],"correctIndex":1},{"question":"Яке співвідношення компресій до вдихів?","options":["15:1","30:2","10:2","50:5"],"correctIndex":1},{"question":"Яка частота компресій?","options":["60-80 на хвилину","100-120 на хвилину","140-160 на хвилину","40-60 на хвилину"],"correctIndex":1}]}'),
('civ-2-3', 'civ-2', 'checklist', 'Чеклист: СЛР алгоритм', 240, 2, 10, '{"steps":[{"title":"Перевірте свідомість","description":"Потрусіть за плечі, гучно запитайте: Ви мене чуєте?"},{"title":"Викличте 103","description":"Або попросіть когось зателефонувати та принести AED"},{"title":"Відкрийте дихальні шляхи","description":"Закиньте голову назад, підніміть подборіддя"},{"title":"Перевірте дихання","description":"Дивіться, слухайте, відчувайте — не довше 10 секунд"},{"title":"Почніть компресії","description":"30 компресій глибиною 5-6 см, частота 100-120/хв"},{"title":"2 вдихи","description":"Затисніть ніс, зробіть 2 вдихи рот-у-рот"},{"title":"Продовжуйте цикл 30:2","description":"Не зупиняйтесь до приїзду медиків або появи AED"}]}'),
('civ-3-1', 'civ-3', 'theory', 'Типи кровотеч', 300, 0, 10, '{"title":"Типи кровотеч","blocks":[{"type":"heading","text":"Розпізнавання кровотеч","level":1},{"type":"text","text":"Правильне визначення типу кровотечі допомагає обрати правильний метод зупинки."},{"type":"heading","text":"Артеріальна кровотеча","level":2},{"type":"text","text":"Яскраво-червона кров, б''є пульсуючим струменем. Найнебезпечніша — смерть може настати за кілька хвилин."},{"type":"warning","text":"Артеріальна кровотеча вимагає негайного накладання турнікету або тиснучої пов''язки!"},{"type":"heading","text":"Венозна кровотеча","level":2},{"type":"text","text":"Темно-червона кров, тече рівномірно. Зупиняється тиснучою пов''язкою."},{"type":"heading","text":"Капілярна кровотеча","level":2},{"type":"text","text":"Кров виступає краплями. Зупиняється самостійно або простою пов''язкою."},{"type":"info","text":"Пряме тиснення на рану — перший і найпростіший метод зупинки будь-якої кровотечі."}],"keyTerms":["Артеріальна кровотеча","Венозна кровотеча","Капілярна кровотеча","Тиснуча пов''язка","Пряме тиснення"]}'),
('civ-3-2', 'civ-3', 'quiz', 'Тест: Кровотечі', 180, 1, 10, '{"questions":[{"question":"Яка кровотеча найнебезпечніша?","options":["Капілярна","Венозна","Артеріальна","Всі однаково"],"correctIndex":2},{"question":"Як виглядає артеріальна кровотеча?","options":["Темна кров, тече рівномірно","Яскраво-червона, б''є струменем","Кров краплями","Чорна кров"],"correctIndex":1},{"question":"Який перший метод зупинки кровотечі?","options":["Турнікет","Джгут","Пряме тиснення на рану","Підняти кінцівку"],"correctIndex":2}]}'),
('civ-3-3', 'civ-3', 'checklist', 'Чеклист: Тиснуча пов''язка', 240, 2, 10, '{"steps":[{"title":"Одягніть рукавички","description":"Захистіть себе від контакту з кров''ю"},{"title":"Визначте тип кровотечі","description":"Артеріальна (пульсуюча), венозна (рівномірна), капілярна (краплі)"},{"title":"Пряме тиснення","description":"Натисніть на рану стерильною серветкою"},{"title":"Тиснуча пов''язка","description":"Накладіть тугу пов''язку поверх серветки"},{"title":"Перевірте ефективність","description":"Кровотеча має зупинитись або значно зменшитись"}]}')
